#include <stdio.h>
#include <stdlib.h>

int compare(const void *p1, const void *p2) {
    const int *a = *(const int **)p1;
    const int *b = *(const int **)p2;
    int len1 = a[0];
    int len2 = b[0];
    int min = len1 < len2 ? len1 : len2;
    for (int i = 1; i <= min; ++i) {
        if (a[i] < b[i]) return -1;
        if (a[i] > b[i]) return 1;
    }
    return len1 - len2;
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int arr[20];
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        int total = n * (n + 1) / 2;
        int **subs = (int **)malloc(total * sizeof(int *));
        int idx = 0;
        for (int i = 0; i < n; ++i) {
            for (int j = i; j < n; ++j) {
                int len = j - i + 1;
                int *sub = (int *)malloc((len + 1) * sizeof(int));
                sub[0] = len; // store length at position 0
                for (int k = 0; k < len; ++k) sub[k + 1] = arr[i + k];
                subs[idx++] = sub;
            }
        }
        qsort(subs, total, sizeof(int *), compare);
        for (int i = 0; i < total; ++i) {
            int len = subs[i][0];
            for (int j = 1; j <= len; ++j) {
                printf("%d", subs[i][j]);
                if (j < len) printf(" ");
            }
            printf("\n");
            free(subs[i]);
        }
        free(subs);
    }
    return 0;
}

