#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        int n; cin>>n;
        vector<int> a(n);
        for(int &x: a) cin>>x;
        vector<vector<int>> subs;
        for(int i=0;i<n;++i){
            for(int j=i;j<n;++j){
                subs.emplace_back(a.begin()+i, a.begin()+j+1);
            }
        }
        auto cmp = [](const vector<int>&x, const vector<int>&y){
            size_t m=min(x.size(), y.size());
            for(size_t i=0;i<m;++i){
                if(x[i]!=y[i]) return x[i]<y[i];
            }
            return x.size()<y.size();
        };
        sort(subs.begin(), subs.end(), cmp);
        for(const auto &v: subs){
            for(size_t i=0;i<v.size();++i){
                if(i) cout<<' ';
                cout<<v[i];
            }
            cout<<'\n';
        }
    }
    return 0;
}

