import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        subs = []
        for i in range(n):
            for j in range(i, n):
                subs.append(arr[i:j+1])
        subs.sort(key=lambda x: (x, len(x)))  # Python compares lists lexicographically, then length tie-breaker
        for sub in subs:
            out_lines.append(' '.join(map(str, sub)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

