    for (let j = i; j < n; ++j) {
      subs.push(arr.slice(i, j + 1));
    }
  }
  subs.sort((a, b) => {
    const m = a.length < b.length ? a.length : b.length;
    for (let i = 0; i < m; ++i) {
      if (a[i] < b[i]) return -1;
      if (a[i] > b[i]) return 1;
    }
    return a.length - b.length;
  });
  for (const sub of subs) {
    output.push(sub.join(' '));
  }
